// Valida payload de entrada.
// Esperado: company_id, contact_id, conversation_id (opcional), message_id (ID externo do WhatsApp, text), received_at.
const input = $input.first().json;

const company_id           = input.company_id      || null;
const contact_id           = input.contact_id      || null;
const conversation_id      = input.conversation_id || null;
const external_message_id  = input.message_id      || null;  // ID externo WhatsApp (string hex)
const received_at          = input.received_at     || new Date().toISOString();

if (!company_id) {
  console.log('[follow_up_rpc_error] inbound_response: company_id ausente');
  return [{ json: { skip: true, reason: 'no_company_id' } }];
}
if (!contact_id) {
  console.log('[follow_up_rpc_error] inbound_response: contact_id ausente');
  return [{ json: { skip: true, reason: 'no_contact_id' } }];
}

console.log('[follow_up_check_started] inbound_response' +
  ' company_id='         + company_id +
  ' contact_id='         + contact_id +
  ' conversation_id='    + conversation_id +
  ' external_message_id=' + external_message_id);

return [{
  json: {
    company_id,
    contact_id,
    conversation_id,
    external_message_id,
    received_at,
    skip: false
  }
}];

