// Interpreta e loga resultado da atribuição.
// attributed=true: resposta foi atribuída ao follow-up ativo — ciclo encerrado.
// attributed=false: resposta fora da janela ou sem follow-up ativo — fluxo normal.
const input   = $input.first().json;
const ctx     = $('validate_inbound_payload').first().json;

if (input && input.attributed === true) {
  console.log('[follow_up_response_attributed]' +
    ' company_id='         + ctx.company_id +
    ' contact_id='         + ctx.contact_id +
    ' conversation_id='    + ctx.conversation_id +
    ' follow_up_event_id=' + input.follow_up_event_id +
    ' attempt_number='     + input.attempt_number +
    ' response_lag_sec='   + input.response_lag_seconds);
} else if (input && input.attributed === false) {
  console.log('[follow_up_response_not_attributed]' +
    ' company_id='      + ctx.company_id +
    ' contact_id='      + ctx.contact_id +
    ' conversation_id=' + ctx.conversation_id +
    ' (fora da janela ou sem follow-up ativo)');
} else {
  console.log('[follow_up_rpc_error] register_follow_up_response inesperado: ' + JSON.stringify(input));
}

return [{ json: {
  success:            input ? input.success            : false,
  attributed:         input ? input.attributed         : false,
  follow_up_event_id: input ? input.follow_up_event_id : null,
  attempt_number:     input ? input.attempt_number     : null,
  response_lag_seconds: input ? input.response_lag_seconds : null
}}];
